@app.route('/users', methods=['POST'])
def create_user():
    """Create a new user with APM tracking"""
    data = request.get_json()
    
    if not data or 'username' not in data or 'email' not in data:
        capture_message('Invalid user data received', level='warning')
        return jsonify({'error': 'Username and email are required'}), 400
    
    with capture_span('database.user.create', span_type='db.sqlite.query'):
        conn = get_db_connection()
        cursor = conn.cursor()
        
        try:
            cursor.execute(
                'INSERT INTO users (username, email) VALUES (?, ?)',
                (data['username'], data['email'])
            )
            user_id = cursor.lastrowid
            conn.commit()
            
            set_custom_context({
                'user_created': {
                    'id': user_id,
                    'username': data['username']
                }
            })
            
        except sqlite3.IntegrityError as e:
            conn.rollback()
            capture_message(f'Database error: {str(e)}', level='error')
            return jsonify({'error': 'Database error'}), 500
        finally:
            conn.close()
    
    return jsonify({
        'id': user_id,
        'username': data['username'],
        'email': data['email']
    }), 201

@app.route('/users/<int:user_id>', methods=['GET'])
def get_user(user_id):
    """Get user by ID with APM tracking"""
    set_custom_context({'user_id': user_id})
    
    with capture_span('database.user.get', span_type='db.sqlite.query'):
        conn = get_db_connection()
        user = conn.execute('SELECT * FROM users WHERE id = ?', (user_id,)).fetchone()
        conn.close()
    
    if user is None:
        capture_message(f'User not found: {user_id}', level='info')
        return jsonify({'error': 'User not found'}), 404
    
    set_user_context(
        user_id=str(user['id']),
        username=user['username'],
        email=user['email']
    )
    
    return jsonify(dict(user)), 200

@app.route('/users', methods=['GET'])
def get_all_users():
    """Get all users with pagination and APM tracking"""
    page = request.args.get('page', 1, type=int)
    per_page = request.args.get('per_page', 10, type=int)
    offset = (page - 1) * per_page
    
    set_custom_context({'pagination': {'page': page, 'per_page': per_page}})
    
    with capture_span('database.users.list', span_type='db.sqlite.query'):
        conn = get_db_connection()
        users = conn.execute(
            'SELECT * FROM users LIMIT ? OFFSET ?',
            (per_page, offset)
        ).fetchall()
        total = conn.execute('SELECT COUNT(*) as count FROM users').fetchone()['count']
        conn.close()
    
    return jsonify({
        'users': [dict(user) for user in users],
        'total': total,
        'page': page,
        'per_page': per_page
    }), 200

